package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It detects the operating system to use the correct ping flags and parsing logic.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	var cmd *exec.Cmd
	var output []byte
	var err error

	// 1. Construct the command safely based on OS.
	// We do not use "bash -c" to avoid Command Injection vulnerabilities.
	if runtime.GOOS == "windows" {
		// Windows uses "-n" for count
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux and macOS use "-c" for count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// 2. Execute the command
	output, err = cmd.CombinedOutput()
	if err != nil {
		// We return the output in the error to help debug (e.g., "unknown host")
		return 0, fmt.Errorf("ping failed: %w (output: %s)", err, strings.TrimSpace(string(output)))
	}

	// 3. Parse the output
	return parsePingOutput(string(output))
}

func parsePingOutput(output string) (float64, error) {
	lines := strings.Split(output, "\n")

	if runtime.GOOS == "windows" {
		// Windows Output Example: "    Minimum = 23ms, Maximum = 24ms, Average = 23ms"
		// We look for "Average ="
		re := regexp.MustCompile(`Average = (\d+)ms`)
		for _, line := range lines {
			if matches := re.FindStringSubmatch(line); len(matches) > 1 {
				return strconv.ParseFloat(matches[1], 64)
			}
		}
	} else {
		// Linux Output: "rtt min/avg/max/mdev = 10.123/20.456/30.789/1.000 ms"
		// macOS Output: "round-trip min/avg/max/stddev = 10.123/20.456/30.789/1.000 ms"

		// We look for the line containing "min/avg/max". 
		// The regex captures the second number in the slash-delimited sequence (the average).
		// Pattern: equals sign, optional whitespace, float/int, slash, (CAPTURE GROUP), slash
		re := regexp.MustCompile(`=\s*[\d.]+/([\d.]+)/`)

		for _, line := range lines {
			if strings.Contains(line, "min/avg/max") {
				matches := re.FindStringSubmatch(line)
				if len(matches) > 1 {
					return strconv.ParseFloat(matches[1], 64)
				}
			}
		}
	}

	return 0, errors.New("could not find average latency statistics in ping output")
}

func main() {
	// Example usage
	host := "google.com"
	count := 3

	fmt.Printf("Pinging %s %d times...\n", host, count)
	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average Latency: %.2f ms\n", avgLatency)
}

