package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Security Fix: Use exec.Command directly with arguments to prevent shell injection.
	// Do not use "bash -c" with formatted strings containing user input.
	// Note: This assumes a Unix-like environment (Linux/macOS) where '-c' sets the count.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	output, err := cmd.CombinedOutput()
	if err != nil {
		// Include output in error to help debug (e.g. "unknown host" or "network unreachable")
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, string(output))
	}

	return parsePingOutput(string(output))
}

// parsePingOutput extracts the average latency from the ping command output.
func parsePingOutput(output string) (float64, error) {
	// Regex explanation:
	// (?:rtt|round-trip) -> Non-capturing group for Linux ("rtt") or macOS ("round-trip") prefix
	// \s*=\s*            -> Matches " = " with optional whitespace
	// [\d.]+             -> Matches the min value
