	if len(matches) < 2 {
		return 0, errors.New("could not find average latency statistics in ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency value '%s': %w", avgStr, err)
	}

	return avg, nil
}

