// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Security Fix: Validate hostname format to prevent Argument Injection (e.g., passing flags like -f).
	// This regex allows alphanumeric characters, dots, hyphens, colons (for IPv6), and underscores.
	validHost := regexp.MustCompile(`^[a-zA-Z0-9:._-]+$`)
	if !validHost.MatchString(host) {
		return 0, errors.New("invalid hostname format")
	}

	// Security Fix: Avoid using "bash -c" to prevent Command Injection.
	// Pass arguments directly to exec.Command so the OS treats them as data, not code.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	output, err := cmd.CombinedOutput()
	if err != nil {
		// It is often useful to return the output even on error, as ping returns non-zero on packet loss
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using regex
	// Expected format: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// We use [\d.]+ to capture the number to be more robust than \d+\.\d+
	re := regexp.MustCompile(`rtt min/avg/max/mdev = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Example usage
	avg, err := MeasureLatency("127.0.0.1", 3)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Average Latency: %.3f ms\n", avg)
}

