	}

	// Execute the command and capture combined output (stdout and stderr)
	output, err = cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v, output: %s", err, string(output))
	}

	return parsePingOutput(string(output))
}

// parsePingOutput extracts the average latency from the ping command output string.
func parsePingOutput(output string) (float64, error) {
	var avgStr string

	if runtime.GOOS == "windows" {
		// Windows output example: "Minimum = 20ms, Maximum = 22ms, Average = 21ms"
		// Note: This regex assumes English locale.
		re := regexp.MustCompile(`Average\s*=\s*(\d+)ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) < 2 {
			return 0, errors.New("could not parse average latency from windows ping output")
		}
		avgStr = matches[1]
	} else {
