		// The regex matches the second number in the slash-separated sequence.
		re := regexp.MustCompile(`min/avg/max/(?:mdev|stddev)\s*=\s*[\d\.]+/([\d\.]+)/`)
		matches := re.FindStringSubmatch(output)
		if len(matches) < 2 {
			return 0, errors.New("could not parse average latency from unix ping output")
		}
		avgStr = matches[1]
	}

	// Convert parsed string to float64
