package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It handles OS-specific differences between Windows and Unix-like systems.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	var cmd *exec.Cmd
	var output []byte
	var err error

	// 1. Construct the command safely based on OS to prevent injection and ensure compatibility.
	if runtime.GOOS == "windows" {
		// Windows uses '-n' for count
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux/macOS uses '-c' for count
		// We call the binary directly rather than using "bash -c" to prevent shell injection.
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// 2. Execute the command
	output, err = cmd.CombinedOutput()
	if err != nil {
		// Note: ping returns non-zero exit code if packets are lost, so we include output in error
		return 0, fmt.Errorf("ping command failed: %w (output: %s)", err, string(output))
	}

	outputStr := string(output)

	// 3. Parse output based on OS
	if runtime.GOOS == "windows" {
		return parseWindowsOutput(outputStr)
	}
	return parseUnixOutput(outputStr)
}

func parseWindowsOutput(output string) (float64, error) {
	// Example Windows output: "Minimum = 10ms, Maximum = 20ms, Average = 15ms"
	// We look for "Average = Xms"
	re := regexp.MustCompile(`Average = (\d+)ms`)
	matches := re.FindStringSubmatch(output)
	if len(matches) < 2 {
		return 0, errors.New("could not find average latency in windows ping output")
	}

	avg, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse float: %w", err)
	}
	return avg, nil
}

func parseUnixOutput(output string) (float64, error) {
	// Linux Example: "rtt min/avg/max/mdev = 10.123/20.456/30.789/1.000 ms"
	// macOS Example: "round-trip min/avg/max/stddev = 10.123/20.456/30.789/1.000 ms"

	// Regex breakdown:
	// (?:rtt|round-trip)      -> Match "rtt" or "round-trip" (non-capturing)
	// .* =                    -> Match until the equals sign
	// \s*                     -> Optional whitespace
	// \d+\.\d+/               -> Match min value and slash
	// ([\d.]+)                -> Capture avg value (digits and dots)
	// /                       -> Match trailing slash
	re := regexp.MustCompile(`(?:rtt|round-trip).*=\s*\d+\.\d+/([\d.]+)/`)

	matches := re.FindStringSubmatch(output)
	if len(matches) < 2 {
		return 0, errors.New("could not find average latency in unix ping output")
	}

	avg, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse float: %w", err)
	}
	return avg, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 3

	fmt.Printf("Pinging %s %d times...\n", host, count)
	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

