package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd
	var out []byte
	var err error

	// 1. Configure the ping command based on the Operating System.
	// Windows uses '-n' for count, while Unix-like systems (Linux/macOS) use '-c'.
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// 2. Execute the command and capture combined output (stdout + stderr).
	out, err = cmd.CombinedOutput()
	outputStr := string(out)

	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, outputStr)
	}

	// 3. Parse the output to extract average latency.
	var avgLatency float64
	var parseErr error

	if runtime.GOOS == "windows" {
		// Windows output example: "Minimum = 20ms, Maximum = 22ms, Average = 21ms"
		// We look for "Average = Xms"
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(outputStr)
		if len(matches) < 2 {
			return 0, fmt.Errorf("could not parse average latency from Windows ping output")
		}
		avgLatency, parseErr = strconv.ParseFloat(matches[1], 64)
	} else {
		// Linux/macOS output example:
		// "rtt min/avg/max/mdev = 20.000/21.500/23.000/1.000 ms"
		// We look for the pattern "= min/avg/max" and extract the second number.
		// Regex explanation:
		// =\s*         : Matches '=' followed by optional whitespace
		// [\d\.]+      : Matches the 'min' value (digits and dots)
		// /            : Matches the separator
		// ([\d\.]+)    : Captures the 'avg' value (Group 1)
		re := regexp.MustCompile(`=\s*[\d\.]+/([\d\.]+)/`)
		matches := re.FindStringSubmatch(outputStr)
		if len(matches) < 2 {
			return 0, fmt.Errorf("could not parse average latency from Unix ping output")
		}
		avgLatency, parseErr = strconv.ParseFloat(matches[1], 64)
	}

	if parseErr != nil {
		return 0, fmt.Errorf("failed to convert latency to float: %w", parseErr)
	}

	return avgLatency, nil
}

func main() {
	// Configuration
	targetHost := "google.com"
	pingCount := 4

	fmt.Printf("Measuring latency to %s with %d attempts...\n", targetHost, pingCount)

	avg, err := MeasureLatency(targetHost, pingCount)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average Latency: %.2f ms\n", avg)
}

