// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
// It supports both Windows and Unix-like (Linux/macOS) systems.
func MeasureLatency(host string, count int) (float64, error) {
	if count < 1 {
		return 0, errors.New("ping count must be at least 1")
	}

	var cmd *exec.Cmd
	var output []byte
	var err error

	// 1. Configure command based on Operating System
	switch runtime.GOOS {
	case "windows":
		// Windows uses -n for count
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		// Linux/macOS uses -c for count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// 2. Execute the command
	// CombinedOutput captures both stdout and stderr
	output, err = cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w\nOutput: %s", err, string(output))
	}

	// 3. Parse the output based on OS
	outputStr := string(output)
	var avgLatency float64
	var parseErr error

	if runtime.GOOS == "windows" {
		avgLatency, parseErr = parseWindowsOutput(outputStr)
	} else {
		avgLatency, parseErr = parseUnixOutput(outputStr)
	}

	if parseErr != nil {
		return 0, parseErr
	}

	return avgLatency, nil
}

// parseWindowsOutput extracts the average time from Windows ping output.
// Expected format: "Minimum = 10ms, Maximum = 20ms, Average = 15ms"
func parseWindowsOutput(output string) (float64, error) {
	// Regex to find "Average = Xms"
	re := regexp.MustCompile(`Average = (\d+)ms`)
	matches := re.FindStringSubmatch(output)

	if len(matches) < 2 {
		return 0, errors.New("could not parse average latency from windows ping output")
	}

	val, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("invalid latency value: %v", err)
	}

	return val, nil
}

// parseUnixOutput extracts the average time from Linux/macOS ping output.
// Expected format: "rtt min/avg/max/mdev = 10.000/15.500/20.000/2.000 ms"
func parseUnixOutput(output string) (float64, error) {
	// Regex to find "min/avg/max/..." and capture the avg value (2nd number)
	// Supports "mdev" (Linux) and "stddev" (macOS/BSD)
	re := regexp.MustCompile(`min/avg/max/(?:mdev|stddev)\s*=\s*[\d\.]+/([\d\.]+)/`)
	matches := re.FindStringSubmatch(output)

	if len(matches) < 2 {
		return 0, errors.New("could not parse average latency from unix ping output")
	}

	val, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("invalid latency value: %v", err)
	}

	return val, nil
}

