package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

func main() {
	// Example usage
	host := "google.com"
	count := 3

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It supports both Windows and Unix-like (Linux/macOS) systems.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	var cmd *exec.Cmd
	var output []byte
	var err error
	countStr := strconv.Itoa(count)

	// Determine OS to set appropriate ping flags and command
	if runtime.GOOS == "windows" {
		// Windows uses -n for count
		cmd = exec.Command("ping", "-n", countStr, host)
	} else {
		// Linux/macOS uses -c for count
		cmd = exec.Command("ping", "-c", countStr, host)
	}

	// Execute the command
	output, err = cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	return parsePingOutput(string(output))
}

// parsePingOutput extracts the average latency based on the operating system.
func parsePingOutput(output string) (float64, error) {
	var avgStr string

	if runtime.GOOS == "windows" {
		// Windows output example: "Minimum = 14ms, Maximum = 14ms, Average = 14ms"
		// We look for "Average = Xms"
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) < 2 {
			return 0, errors.New("could not parse average latency from Windows ping output")
		}
		avgStr = matches[1]
	} else {
		// Unix output example: "min/avg/max/mdev = 14.123/15.456/16.789/1.234 ms"
		// We look for the pattern "num/num/num" after an equals sign and capture the middle number.
		// This regex is slightly more permissive to handle variations like "round-trip" vs "rtt".
		re := regexp.MustCompile(`=\s*[\d.]+/([\d.]+)/[\d.]+`)
		matches := re.FindStringSubmatch(output)
		if len(matches) < 2 {
			return 0, errors.New("could not parse average latency from Unix ping output")
		}
		avgStr = matches[1]
	}

	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

