import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host a user-defined number of times
// and returns the average latency in milliseconds.
// It supports both Windows and Unix-like (Linux, macOS) operating systems.
func MeasureLatency(host string, count int) (float64, error) {
	if count < 1 {
		return 0, errors.New("ping count must be at least 1")
	}
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}

	var cmd *exec.Cmd
	var output []byte
	var err error

	// Determine command arguments based on the operating system
	if runtime.GOOS == "windows" {
		// Windows uses -n for count
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Unix-like systems (Linux, macOS) use -c for count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command and capture combined standard output and standard error
	output, err = cmd.CombinedOutput()
	if err != nil {
		// If the command fails (e.g., host unreachable, DNS error), return the error
		return 0, fmt.Errorf("failed to execute ping: %v\nOutput: %s", err, string(output))
	}

	outputStr := string(output)

	// Parse the output based on the OS format
	if runtime.GOOS == "windows" {
		return parseWindowsOutput(outputStr)
	}
	return parseUnixOutput(outputStr)
}

// parseWindowsOutput extracts the average latency from Windows ping output.
// Example output fragment: "Minimum = 20ms, Maximum = 22ms, Average = 21ms"
func parseWindowsOutput(output string) (float64, error) {
	// Regex to find "Average = Xms"
	re := regexp.MustCompile(`Average = (\d+)ms`)
	matches := re.FindStringSubmatch(output)

	if len(matches) < 2 {
		return 0, errors.New("could not parse average latency from Windows ping output (check for packet loss)")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert latency to float: %v", err)
	}

	return avg, nil
}

// parseUnixOutput extracts the average latency from Linux/macOS ping output.
// Example output fragment: "rtt min/avg/max/mdev = 20.100/21.500/22.900/1.200 ms"
func parseUnixOutput(output string) (float64, error) {
	// Regex to find the standard statistics line.
	// It looks for "min/avg/max/..." followed by numbers.
	// We capture the second number (avg).
	// Handles "mdev" (Linux) and "stddev" (macOS/BSD).
	re := regexp.MustCompile(`min/avg/max/(?:mdev|stddev)\s*=\s*[\d\.]+/([\d\.]+)/`)
	matches := re.FindStringSubmatch(output)

	if len(matches) < 2 {
		return 0, errors.New("could not parse average latency from Unix ping output (check for packet loss)")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert latency to float: %v", err)
	}

	return avg, nil
}

func main() {
	// Configuration
	targetHost := "google.com"
	pingCount := 4

	fmt.Printf("Pinging %s %d times...\n", targetHost, pingCount)

	latency, err := MeasureLatency(targetHost, pingCount)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average Latency to %s: %.2f ms\n", targetHost, latency)
}

