// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
// It supports both Windows and Unix-like (Linux/macOS) systems by detecting the OS and adjusting command flags/parsing.
func MeasureLatency(host string, count int) (float64, error) {
	if count < 1 {
		return 0, fmt.Errorf("count must be at least 1")
	}

	var cmd *exec.Cmd
	var output []byte
	var err error

	// Determine OS to set specific ping flags and parsing logic
	if runtime.GOOS == "windows" {
		// Windows: ping -n <count> <host>
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Unix-like (Linux/macOS): ping -c <count> <host>
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
		// Force English output for consistent parsing on Unix systems
		cmd.Env = append(os.Environ(), "LC_ALL=C")
	}

	// Execute the command
	output, err = cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v, output: %s", err, string(output))
	}

	// Parse the output based on OS
	if runtime.GOOS == "windows" {
		return parseWindowsOutput(string(output))
	}
	return parseUnixOutput(string(output))
}

// parseWindowsOutput extracts the average latency from Windows ping output.
// Expected format: "Average = 20ms"
func parseWindowsOutput(output string) (float64, error) {
	// Regex to capture the integer value before "ms" in the Average section
	re := regexp.MustCompile(`Average = (\d+)ms`)
	matches := re.FindStringSubmatch(output)

	if len(matches) < 2 {
		return 0, fmt.Errorf("could not parse average latency from Windows output")
	}

	val, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert latency to float: %v", err)
	}
	return val, nil
}

// parseUnixOutput extracts the average latency from Linux/macOS ping output.
// Expected format: "min/avg/max/mdev = 10.000/20.000/30.000/5.000 ms"
func parseUnixOutput(output string) (float64, error) {
	// Regex to capture the second number (avg) in the slash-delimited list.
	// Linux uses "mdev", macOS/BSD uses "stddev".
	re := regexp.MustCompile(`min/avg/max/(?:mdev|stddev)\s*=\s*[\d\.]+/([\d\.]+)/`)
	matches := re.FindStringSubmatch(output)

	if len(matches) < 2 {
		return 0, fmt.Errorf("could not parse average latency from Unix output")
	}

	val, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert latency to float: %v", err)
	}
	return val, nil
}

func main() {
	// Configuration
	host := "google.com"
	count := 4

	fmt.Printf("Measuring latency to %s with %d attempts...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average Latency: %.2f ms\n", avgLatency)
}

