package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Security Fix: Use exec.Command directly with arguments to prevent shell injection.
	// Do not use "bash -c" with formatted strings.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	output, err := cmd.CombinedOutput()
	if err != nil {
		// This handles cases where ping exits with non-zero status (e.g., host unreachable)
		return 0, fmt.Errorf("failed to execute ping: %w", err)
	}

	outputStr := string(output)

	// Extract average latency using regex.
	// Target format (Linux): rtt min/avg/max/mdev = 0.000/0.000/0.000/0.000 ms
	// We match "rtt ... = ", ignore the first number (min), and capture the second number (avg).
	// [0-9.]+ handles both floating points and integers.
	re := regexp.MustCompile(`rtt min/avg/max/mdev = [0-9.]+/([0-9.]+)/`)
	matches := re.FindStringSubmatch(outputStr)

	if len(matches) < 2 {
		return 0, errors.New("could not find average latency in ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Example usage
	host := "127.0.0.1"
	avg, err := MeasureLatency(host, 4)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}
	fmt.Printf("Average latency to %s: %.3f ms\n", host, avg)
}

