package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count < 1 {
		return 0, fmt.Errorf("count must be at least 1")
	}

	var cmd *exec.Cmd
	var output []byte
	var err error

	// Determine command flags based on the operating system
	switch runtime.GOOS {
	case "windows":
		// Windows uses -n for count
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		// Linux and macOS (Darwin) use -c for count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command
	output, err = cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v\nOutput: %s", err, string(output))
	}

	return parsePingOutput(string(output))
}

// parsePingOutput extracts the average latency from the ping command output
// based on the operating system format.
func parsePingOutput(output string) (float64, error) {
	var avgLatencyStr string

	if runtime.GOOS == "windows" {
		// Windows Output Example: "Minimum = 20ms, Maximum = 22ms, Average = 21ms"
		// Regex to capture the integer following "Average ="
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) < 2 {
			return 0, fmt.Errorf("failed to parse average latency from Windows output")
		}
		avgLatencyStr = matches[1]
	} else {
		// Unix/Linux/Mac Output Example: "rtt min/avg/max/mdev = 20.100/21.500/22.900/1.200 ms"
		// Regex to capture the second number in the slash-separated list (min/avg/max)
		re := regexp.MustCompile(`min/avg/max/(?:mdev|stddev) = [\d\.]+/([\d\.]+)/`)
		matches := re.FindStringSubmatch(output)
		if len(matches) < 2 {
			return 0, fmt.Errorf("failed to parse average latency from Unix output")
		}
		avgLatencyStr = matches[1]
	}

	// Convert parsed string to float64
	latency, err := strconv.ParseFloat(avgLatencyStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert latency to float: %v", err)
	}

	return latency, nil
}

func main() {
	// Configuration
	targetHost := "google.com"
	pingCount := 4

	fmt.Printf("Pinging %s %d times...\n", targetHost, pingCount)

	avgLatency, err := MeasureLatency(targetHost, pingCount)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average Latency to %s: %.2f ms\n", targetHost, avgLatency)
}

