// MeasureLatency pings the specified host a user-defined number of times
// and returns the average latency in milliseconds.
// It uses the system's native 'ping' command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	if count < 1 {
		return 0, errors.New("count must be at least 1")
	}

	if strings.TrimSpace(host) == "" {
		return 0, errors.New("host cannot be empty")
	}

	var cmd *exec.Cmd
	var output []byte
	var err error

	// Determine command arguments based on the operating system
	switch runtime.GOOS {
	case "windows":
		// Windows uses -n for count
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	case "linux", "darwin":
		// Linux and macOS use -c for count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	// Execute the command and capture combined output (stdout and stderr)
	output, err = cmd.CombinedOutput()
	if err != nil {
		// If the command fails (e.g., host unreachable), return the error with output for context
		return 0, fmt.Errorf("ping failed: %v, output: %s", err, string(output))
	}

	return parsePingOutput(string(output))
}

// parsePingOutput extracts the average latency from the ping command output
func parsePingOutput(output string) (float64, error) {
	if runtime.GOOS == "windows" {
		// Windows output example: "Minimum = 15ms, Maximum = 15ms, Average = 15ms"
		// We look for "Average = Xms"
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) > 1 {
			return strconv.ParseFloat(matches[1], 64)
		}
	} else {
		// Linux/macOS output example: "rtt min/avg/max/mdev = 10.000/15.000/20.000/1.000 ms"
		// We look for the slash-delimited numbers after the equals sign.
		// The second number is the average.
		re := regexp.MustCompile(`= [\d\.]+/([\d\.]+)/`)
		matches := re.FindStringSubmatch(output)
		if len(matches) > 1 {
			return strconv.ParseFloat(matches[1], 64)
		}
	}

	return 0, errors.New("could not parse average latency from ping output")
}

func main() {
	// Configuration
	targetHost := "google.com"
	pingCount := 4

