package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// SECURITY FIX:
	// Previously, the code used `bash -c` with fmt.Sprintf, which allowed Command Injection
	// if the 'host' variable contained shell operators (e.g., "google.com; rm -rf /").
	// We now pass arguments directly to the command, which treats 'host' strictly as an argument.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	return parsePingOutput(string(output))
}

// parsePingOutput extracts the average latency from the raw ping output.
func parsePingOutput(output string) (float64, error) {
	lines := strings.Split(output, "\n")
	var statsLine string

	// Find the line containing the statistics.
	// Standard Linux output: "rtt min/avg/max/mdev = ..."
	// macOS/BSD output: "round-trip min/avg/max/stddev = ..."
	for _, line := range lines {
		if strings.Contains(line, "min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using regex.
	// We look for the pattern " = min/avg/max/..." and capture the second group (avg).
	// We use [\d.]+ to handle both integers (e.g., "10") and floats (e.g., "10.5").
	re := regexp.MustCompile(`=\s*[\d.]+/([\d.]+)/`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 3

	fmt.Printf("Pinging %s %d times...\n", host, count)
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average Latency: %.3f ms\n", avg)
}

