package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd
	var out []byte
	var err error

	// Determine command flags based on OS
	// Windows uses -n for count, Unix-likes use -c
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command
	out, err = cmd.CombinedOutput()
	if err != nil {
		return 0.0, fmt.Errorf("failed to execute ping: %v\nOutput: %s", err, string(out))
	}

	return parseAverageLatency(string(out))
}

// parseAverageLatency extracts the average time from ping output.
// It handles differences between Windows and Unix-like output formats.
func parseAverageLatency(output string) (float64, error) {
	if runtime.GOOS == "windows" {
		// Windows output example: "Minimum = 10ms, Maximum = 12ms, Average = 11ms"
		// Note: This assumes English locale.
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) < 2 {
			return 0.0, fmt.Errorf("could not parse average latency from Windows ping output")
		}
		return strconv.ParseFloat(matches[1], 64)
	}

	// Unix/Linux/macOS output example:
	// "round-trip min/avg/max/stddev = 10.000/11.500/13.000/1.000 ms"
	// or "rtt min/avg/max/mdev = ..."
	re := regexp.MustCompile(`min/avg/max/(?:mdev|stddev)\s*=\s*[\d\.]+/([\d\.]+)/`)
	matches := re.FindStringSubmatch(output)
	if len(matches) < 2 {
		return 0.0, fmt.Errorf("could not parse average latency from Unix ping output")
	}

	return strconv.ParseFloat(matches[1], 64)
}

func main() {
	// Configuration
	targetHost := "google.com"
	pingCount := 4

	fmt.Printf("Measuring latency to %s with %d attempts...\n", targetHost, pingCount)

	avgLatency, err := MeasureLatency(targetHost, pingCount)
	if err != nil {
		// Check if it's a "command not found" or network error
		if strings.Contains(err.Error(), "executable file not found") {
			fmt.Println("Error: 'ping' command not found on this system.")
		} else {
			fmt.Printf("Error measuring latency: %v\n", err)
		}
		return
	}

	fmt.Printf("Average Latency: %.2f ms\n", avgLatency)
}

