// MeasureLatency pings the specified host a user-defined number of times
// and returns the average latency in milliseconds.
// It uses the system's native 'ping' command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	if count < 1 {
		return 0, fmt.Errorf("count must be at least 1")
	}

	var cmd *exec.Cmd
	var out []byte
	var err error

	// Construct the command based on the operating system
	switch runtime.GOOS {
	case "windows":
		// Windows: ping -n <count> <host>
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		// Linux/macOS/Unix: ping -c <count> <host>
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command and capture combined standard output and standard error
	out, err = cmd.CombinedOutput()
	if err != nil {
		// If the command fails (e.g., host unreachable, timeout), return the error
		// Note: ping returns a non-zero exit code if packets are lost or host is unreachable.
		return 0, fmt.Errorf("ping command failed: %v, output: %s", err, string(out))
	}

	outputStr := string(out)
	return parseAverageLatency(outputStr)
}

// parseAverageLatency extracts the average time from the raw ping output.
func parseAverageLatency(output string) (float64, error) {
	var avgLatency float64
	var parseErr error

	if runtime.GOOS == "windows" {
		// Windows Output Example: "    Minimum = 20ms, Maximum = 22ms, Average = 21ms"
		// We look for "Average = Xms"
		// Note: This assumes the system language is English.
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(output)

		if len(matches) >= 2 {
			avgLatency, parseErr = strconv.ParseFloat(matches[1], 64)
		} else {
			return 0, fmt.Errorf("could not find average latency in windows ping output")
		}

	} else {
		// Unix/Linux/macOS Output Example: "rtt min/avg/max/mdev = 20.100/21.500/22.900/1.200 ms"
		// We look for the "min/avg/max..." line and extract the second number.

		// Pattern explanation:
		// min/avg/max/(?:mdev|stddev) -> Matches the header (mdev on Linux, stddev on BSD/macOS)
		// \s*=\s*                     -> Matches " = " with optional whitespace
		// [\d\.]+                     -> Matches min value (ignored)
		// /                           -> Separator
		// ([\d\.]+)                   -> Captures the AVG value
		re := regexp.MustCompile(`min/avg/max/(?:mdev|stddev)\s*=\s*[\d\.]+/([\d\.]+)/`)
		matches := re.FindStringSubmatch(output)

		if len(matches) >= 2 {
			avgLatency, parseErr = strconv.ParseFloat(matches[1], 64)
		} else {
			return 0, fmt.Errorf("could not find average latency in unix ping output")
		}
	}

	if parseErr != nil {
		return 0, fmt.Errorf("failed to parse latency value: %v", parseErr)
	}

	return avgLatency, nil
}

func main() {
	// Configuration
	targetHost := "google.com"
	pingCount := 4

	fmt.Printf("Pinging %s %d times...\n", targetHost, pingCount)

	// Execute measurement
	avg, err := MeasureLatency(targetHost, pingCount)
	if err != nil {
