fix.generatedCode:
package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Security Fix: Do not use "bash -c" with formatted strings as it is vulnerable to Command Injection.
	// Pass arguments directly to exec.Command.
	// Note: This command syntax ("-c") works on Linux and macOS. Windows would require "-n".
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	outputStr := string(output)

	// Regex Explanation:
	// 1. (?:rtt|round-trip): Matches "rtt" (Linux) or "round-trip" (macOS/BSD).
	// 2. min/avg/max/(?:mdev|stddev): Matches the header, accepting "mdev" or "stddev".
	// 3. \s*=\s*: Matches the equals sign with optional whitespace.
	// 4. [0-9.]+: Matches the minimum value (ignored).
	// 5. /([0-9.]+)/: Captures the average value (the target).
	re := regexp.MustCompile(`(?:rtt|round-trip) min/avg/max/(?:mdev|stddev)\s*=\s*[0-9.]+/([0-9.]+)/`)

	matches := re.FindStringSubmatch(outputStr)
	if len(matches) < 2 {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	host := "google.com"
	count := 3

	fmt.Printf("Pinging %s %d times...\n", host, count)
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average Latency: %.3f ms\n", avg)
}

