package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec.
// SECURITY FIX: Arguments are passed directly to exec.Command to prevent Command Injection.
func MeasureLatency(host string, count int) (float64, error) {
	// Basic Input Validation
	if strings.TrimSpace(host) == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// SECURITY FIX:
	// 1. Do not use "bash -c" or "sh -c". Run the binary directly.
	// 2. Pass arguments as separate strings. This prevents the OS from interpreting
	//    the 'host' string as shell commands, neutralizing command injection attacks.
	countStr := strconv.Itoa(count)
	cmd := exec.Command("ping", "-c", countStr, host)

	output, err := cmd.CombinedOutput()
	if err != nil {
		// We return the output in the error to help debug (e.g., "unknown host")
		// but be careful not to expose sensitive system info in production logs if unrelated to ping.
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		// Note: The specific output string "rtt min/avg/max" depends on the OS/ping version (usually iputils-ping on Linux).
		if strings.Contains(line, "rtt min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using regex
	// Example line: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	re := regexp.MustCompile(`rtt min/avg/max/mdev = \d+\.\d+/([\d.]+)/\d+\.\d+/\d+\.\d+ ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Example usage
	host := "127.0.0.1"
	avg, err := MeasureLatency(host, 4)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Average Latency to %s: %.3f ms\n", host, avg)
}

