package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host a user-defined number of times
// and returns the average latency in milliseconds.
// It handles command arguments and output parsing for both Windows and Unix-like systems.
func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd
	var out []byte
	var err error

	// Determine the command based on the operating system
	switch runtime.GOOS {
	case "windows":
		// Windows: ping -n <count> <host>
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		// Linux/macOS: ping -c <count> <host>
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command and capture combined standard output and standard error
	out, err = cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %v, output: %s", err, string(out))
	}

	return parseAverageLatency(string(out))
}

// parseAverageLatency extracts the average time from the ping command output.
func parseAverageLatency(output string) (float64, error) {
	var avgStr string

	if runtime.GOOS == "windows" {
		// Windows output example: "Minimum = 14ms, Maximum = 16ms, Average = 15ms"
		// Regex to find "Average = Xms"
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) < 2 {
			return 0, fmt.Errorf("could not parse latency from Windows output")
		}
		avgStr = matches[1]
	} else {
		// Unix/Linux/macOS output example:
		// "rtt min/avg/max/mdev = 14.321/15.444/16.987/0.555 ms"
		// Note: macOS might use 'stddev' instead of 'mdev'
		re := regexp.MustCompile(`min/avg/max/(?:mdev|stddev)\s*=\s*[0-9.]+/([0-9.]+)/`)
		matches := re.FindStringSubmatch(output)
		if len(matches) < 2 {
			return 0, fmt.Errorf("could not parse latency from Unix output")
		}
		avgStr = matches[1]
	}

	// Convert the extracted string to float64
	latency, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert latency value '%s' to float: %v", avgStr, err)
	}

	return latency, nil
}

func main() {
	// Configuration
	targetHost := "8.8.8.8" // Google Public DNS
	pingCount := 4

	fmt.Printf("Measuring latency to %s with %d attempts...\n", targetHost, pingCount)

	avgLatency, err := MeasureLatency(targetHost, pingCount)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average Latency: %.2f ms\n", avgLatency)
}

