package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
// It supports both Windows and Unix-like (Linux/macOS) systems by adjusting command flags and output parsing.
func MeasureLatency(host string, count int) (float64, error) {
	if count < 1 {
		return 0, fmt.Errorf("count must be at least 1")
	}

	var cmd *exec.Cmd
	var outputBytes []byte
	var err error

	// Determine command arguments based on OS
	if runtime.GOOS == "windows" {
		// Windows: ping -n <count> <host>
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux/macOS: ping -c <count> <host>
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command
	outputBytes, err = cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w (output: %s)", err, string(outputBytes))
	}

	output := string(outputBytes)
	var avgLatency float64
	found := false

	if runtime.GOOS == "windows" {
		// Windows Output Example: "    Minimum = 20ms, Maximum = 22ms, Average = 21ms"
		// Regex looks for "Average = Xms"
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) > 1 {
			avgLatency, err = strconv.ParseFloat(matches[1], 64)
			if err == nil {
				found = true
			}
		}
	} else {
		// Unix/Linux Output Example: "rtt min/avg/max/mdev = 10.000/20.000/30.000/5.000 ms"
		// macOS Output Example: "round-trip min/avg/max/stddev = ..."
		// Regex looks for the pattern "num/num/num" and captures the middle number (avg)
		// We look for the line containing "min/avg/max" followed by the values.
		re := regexp.MustCompile(`min/avg/max/(?:mdev|stddev)\s*=\s*[\d\.]+/([\d\.]+)/`)
		matches := re.FindStringSubmatch(output)
		if len(matches) > 1 {
			avgLatency, err = strconv.ParseFloat(matches[1], 64)
			if err == nil {
				found = true
			}
		}
	}

	if !found {
		return 0, fmt.Errorf("could not parse average latency from output. Output sample: %s", output)
	}

	return avgLatency, nil
}

func main() {
	// Configuration
	targetHost := "google.com"
	pingCount := 4

	fmt.Printf("Pinging %s %d times...\n", targetHost, pingCount)

	avg, err := MeasureLatency(targetHost, pingCount)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average Latency to %s: %.2f ms\n", targetHost, avg)
}

