fix.generatedCode:
package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// SECURITY FIX: Execute ping directly rather than using a shell (bash -c).
	// This prevents command injection vulnerabilities if the host string contains malicious characters.
	// Note: This assumes a Unix-like environment (Linux/macOS) where '-c' is the flag for count.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	output, err := cmd.CombinedOutput()
	if err != nil {
		// We return the error, but also include the output because ping might return a non-zero exit code
		// on packet loss while still providing some output.
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	outputStr := string(output)

	// Regex to extract the average latency.
	// Linux output: "rtt min/avg/max/mdev = ..."
	// macOS/BSD output: "round-trip min/avg/max/stddev = ..."
	// We capture the second number in the slash-delimited sequence (min/AVG/max).
	re := regexp.MustCompile(`(?:rtt|round-trip) min/avg/max/(?:mdev|stddev)\s*=\s*\d+(?:\.\d+)?/(\d+(?:\.\d+)?)/`)

	matches := re.FindStringSubmatch(outputStr)
	if len(matches) < 2 {
		return 0, errors.New("could not find average latency in ping output")
	}

	// matches[1] contains the captured average string
	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	fmt.Printf("Pinging %s %d times...\n", host, count)
	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average Latency: %.3f ms\n", latency)
}

