package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count < 1 {
		return 0, errors.New("count must be at least 1")
	}
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}

	var cmd *exec.Cmd
	var output []byte
	var err error

	// Determine OS to set specific flags and parsing logic
	switch runtime.GOOS {
	case "windows":
		// Windows uses -n for count
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		// Linux/macOS/Unix uses -c for count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
		// Force English output for consistent regex parsing on Unix systems
		cmd.Env = append(cmd.Env, "LC_ALL=C")
	}

	// Execute the command
	output, err = cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v\nOutput: %s", err, string(output))
	}

	return parsePingOutput(string(output))
}

// parsePingOutput extracts the average latency from the command output
// based on the operating system.
func parsePingOutput(out string) (float64, error) {
	if runtime.GOOS == "windows" {
		// Windows Output Example: "Minimum = 10ms, Maximum = 20ms, Average = 15ms"
		// Regex looks for "Average = Xms"
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(out)
		if len(matches) < 2 {
			return 0, errors.New("could not parse average latency from windows ping output")
		}
		return strconv.ParseFloat(matches[1], 64)
	}

	// Unix Output Example: "rtt min/avg/max/mdev = 10.000/15.500/20.000/2.000 ms"
	// Regex looks for "min/avg/max/mdev = num/num/num/num"
	// We capture the second number (avg)
	re := regexp.MustCompile(`min/avg/max/(?:mdev|stddev) = [\d\.]+/([\d\.]+)/`)
	matches := re.FindStringSubmatch(out)
	if len(matches) < 2 {
		return 0, errors.New("could not parse average latency from unix ping output")
	}
	return strconv.ParseFloat(matches[1], 64)
}

func main() {
	// Configuration
	targetHost := "google.com"
	pingCount := 4

	fmt.Printf("Pinging %s %d times...\n", targetHost, pingCount)

	avgLatency, err := MeasureLatency(targetHost, pingCount)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average Latency to %s: %.2f ms\n", targetHost, avgLatency)
}

