// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
// It supports Windows and Unix-like (Linux, macOS) systems by parsing the standard output of the ping command.
func MeasureLatency(host string, count int) (float64, error) {
	if count < 1 {
		return 0, errors.New("count must be at least 1")
	}

	var cmd *exec.Cmd
	var stdout bytes.Buffer

	// Determine the operating system to construct the correct ping command
	switch runtime.GOOS {
