		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Capture stdout to parse the results
	cmd.Stdout = &stdout

	// Execute the command
	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w", err)
	}

	output := stdout.String()
	return parseAverageLatency(output)
}

// parseAverageLatency extracts the average time from the ping command output.
func parseAverageLatency(output string) (float64, error) {
	var avgStr string

	if runtime.GOOS == "windows" {
		// Windows output format example: "Average = 12ms"
		// We look for "Average =" followed by digits
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) < 2 {
