package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

func main() {
	// Example usage
	host := "google.com"
	count := 3
	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}
	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It supports both Windows and Unix-like systems.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	var cmd *exec.Cmd
	var output []byte
	var err error

	// 1. Construct command based on OS to ensure flags are correct
	// and to avoid using 'bash -c' which introduces shell injection vulnerabilities.
	if runtime.GOOS == "windows" {
		// Windows uses -n for count
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux and macOS use -c for count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// 2. Execute Command
	output, err = cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	outputStr := string(output)

	// 3. Parse Output based on OS
	if runtime.GOOS == "windows" {
		return parseWindowsOutput(outputStr)
	}
	return parseUnixOutput(outputStr)
}

func parseWindowsOutput(output string) (float64, error) {
	// Windows Output Example: "    Minimum = 21ms, Maximum = 22ms, Average = 21ms"
	// We look for "Average = Xms"
	re := regexp.MustCompile(`Average = (\d+)ms`)
	matches := re.FindStringSubmatch(output)
	if len(matches) < 2 {
		return 0, errors.New("could not parse average latency from Windows ping output")
	}

	avg, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency: %w", err)
	}
	return avg, nil
}

func parseUnixOutput(output string) (float64, error) {
	// Linux Example: "rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms"
	// macOS Example: "round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms"

	// We use a regex that ignores the prefix (rtt vs round-trip) and captures the section after " = "
	// Pattern: = min/avg/max/mdev
	// We capture the second group (avg)
	re := regexp.MustCompile(`=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+`)
	matches := re.FindStringSubmatch(output)

	if len(matches) < 2 {
		// Fallback: sometimes ping output might contain errors or different formatting
		if strings.Contains(output, "100% packet loss") {
			return 0, errors.New("100% packet loss")
		}
		return 0, errors.New("could not parse average latency from Unix ping output")
	}

	avg, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency: %w", err)
	}
	return avg, nil
}

