// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
// It supports both Windows and Unix-like systems (Linux, macOS) by adjusting the ping command arguments and output parsing.
func MeasureLatency(host string, count int) (float64, error) {
	if count < 1 {
		return 0, errors.New("count must be at least 1")
	}

	var cmd *exec.Cmd
	var output []byte
	var err error

	// Determine command arguments based on OS
	if runtime.GOOS == "windows" {
		// Windows uses -n for count
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux/macOS uses -c for count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command and capture combined stdout/stderr
	output, err = cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w\nOutput: %s", err, string(output))
	}

	return parsePingOutput(string(output))
}

// parsePingOutput extracts the average latency from the raw ping output string.
func parsePingOutput(output string) (float64, error) {
	if runtime.GOOS == "windows" {
		return parseWindowsOutput(output)
	}
	return parseUnixOutput(output)
}

func parseWindowsOutput(output string) (float64, error) {
	// Windows output example: "Minimum = 18ms, Maximum = 18ms, Average = 18ms"
	// Note: This assumes the system language is English.
	re := regexp.MustCompile(`Average = (\d+)ms`)
	matches := re.FindStringSubmatch(output)

	if len(matches) < 2 {
		return 0, errors.New("could not parse average latency from Windows ping output")
	}

	avg, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("invalid latency value: %v", err)
	}

	return avg, nil
}

func parseUnixOutput(output string) (float64, error) {
	// Linux example: "rtt min/avg/max/mdev = 13.936/13.936/13.936/0.000 ms"
	// macOS example: "round-trip min/avg/max/stddev = 13.936/13.936/13.936/0.000 ms"

	// We look for the pattern number/number/number/number
	// The second number is the average.
	re := regexp.MustCompile(`=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+`)
	matches := re.FindStringSubmatch(output)

	if len(matches) < 2 {
		return 0, errors.New("could not parse average latency from Unix ping output")
	}

	avg, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("invalid latency value: %v", err)
	}

	return avg, nil
}

func main() {
	// Configuration
	targetHost := "google.com"
	pingCount := 4

	fmt.Printf("Pinging %s %d times...\n", targetHost, pingCount)

	avgLatency, err := MeasureLatency(targetHost, pingCount)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average Latency to %s: %.2f ms\n", targetHost, avgLatency)
}

