package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

func main() {
	// Example usage
	host := "google.com"
	count := 3
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}
	fmt.Printf("Average latency to %s: %.2f ms\n", host, avg)
}

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	var cmd *exec.Cmd
	var outputBytes []byte
	var err error

	// Determine OS to set correct ping flags
	// Windows uses -n for count, Unix-like systems use -c
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	outputBytes, err = cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(outputBytes))
	}

	output := string(outputBytes)

	if runtime.GOOS == "windows" {
		return parseWindowsOutput(output)
	}
	return parseUnixOutput(output)
}

// parseUnixOutput handles Linux (rtt) and macOS (round-trip) output formats
func parseUnixOutput(output string) (float64, error) {
	// Linux: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// macOS: round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	// Regex matches "min/avg/max..." and captures the second value (avg)
	re := regexp.MustCompile(`(?:rtt|round-trip) min/avg/max/(?:mdev|stddev)\s*=\s*[\d\.]+/([\d\.]+)/[\d\.]+/[\d\.]+ ms`)

	matches := re.FindStringSubmatch(output)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from unix ping output")
	}

	return strconv.ParseFloat(matches[1], 64)
}

// parseWindowsOutput handles standard Windows ping output
func parseWindowsOutput(output string) (float64, error) {
	// Windows output example:
	// "    Minimum = 23ms, Maximum = 24ms, Average = 23ms"
	re := regexp.MustCompile(`Average = (\d+)ms`)

	matches := re.FindStringSubmatch(output)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from windows ping output")
	}

	return strconv.ParseFloat(matches[1], 64)
}

