package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count < 1 {
		return 0, errors.New("count must be at least 1")
	}

	var cmd *exec.Cmd
	var output []byte
	var err error

	// Determine command arguments based on the operating system.
	// Windows uses "-n" for count, Unix-like systems use "-c".
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command and capture combined standard output and standard error.
	output, err = cmd.CombinedOutput()
	if err != nil {
		// If the command fails (e.g., host unreachable), return the error.
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	return parsePingOutput(string(output))
}

// parsePingOutput extracts the average latency from the ping command output string.
func parsePingOutput(output string) (float64, error) {
	if runtime.GOOS == "windows" {
		// Windows output example: "Minimum = 13ms, Maximum = 13ms, Average = 13ms"
		// We look for "Average = Xms"
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) > 1 {
			return strconv.ParseFloat(matches[1], 64)
		}
	} else {
		// Unix/Linux/macOS output example:
		// "round-trip min/avg/max/stddev = 13.946/13.946/13.946/0.000 ms"
		// or "rtt min/avg/max/mdev = ..."
		// We look for the pattern "= min/avg/max" and capture the second number (avg).
		re := regexp.MustCompile(`=\s*[0-9.]+/([0-9.]+)/`)
		matches := re.FindStringSubmatch(output)
		if len(matches) > 1 {
			return strconv.ParseFloat(matches[1], 64)
		}
	}

	return 0, errors.New("could not parse average latency from ping output")
}

func main() {
	// Configuration
	targetHost := "google.com"
	pingCount := 4

	fmt.Printf("Measuring latency to %s with %d attempts...\n", targetHost, pingCount)

	avgLatency, err := MeasureLatency(targetHost, pingCount)
	if err != nil {
		// Check if it's an exit error (like 100% packet loss) or a parsing error
		if strings.Contains(err.Error(), "ping command failed") {
			fmt.Printf("Network error: %v\n", err)
		} else {
			fmt.Printf("Error: %v\n", err)
		}
		return
	}

	fmt.Printf("Average Latency: %.2f ms\n", avgLatency)
}

