// MeasureLatency pings the specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count < 1 {
		return 0, errors.New("count must be at least 1")
	}

	var cmd *exec.Cmd
	var outputBytes []byte
	var err error

	// Determine command arguments based on the operating system
	if runtime.GOOS == "windows" {
		// Windows uses -n for count
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Unix-like systems (Linux, macOS) use -c for count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command and capture combined stdout/stderr
	outputBytes, err = cmd.CombinedOutput()
	if err != nil {
		// If ping fails (e.g., host unreachable, unknown host), it returns a non-zero exit code
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	output := string(outputBytes)
	return parseAverageLatency(output)
}

// parseAverageLatency extracts the average time from the raw ping output.
func parseAverageLatency(output string) (float64, error) {
	var avgStr string

	if runtime.GOOS == "windows" {
		// Windows output format example:
		// "    Minimum = 23ms, Maximum = 24ms, Average = 23ms"
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) < 2 {
			return 0, errors.New("could not parse latency from windows ping output")
		}
		avgStr = matches[1]
	} else {
		// Linux/macOS output format example:
		// "rtt min/avg/max/mdev = 23.456/24.123/25.789/1.234 ms"
		// Note: The regex handles both 'mdev' (Linux) and 'stddev' (macOS/BSD)
		re := regexp.MustCompile(`min/avg/max/(?:mdev|stddev)\s*=\s*[\d.]+/([\d.]+)/`)
		matches := re.FindStringSubmatch(output)
		if len(matches) < 2 {
			return 0, errors.New("could not parse latency from unix ping output")
		}
		avgStr = matches[1]
	}

	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert latency to float: %w", err)
	}

	return avg, nil
}

